module.render:
const color = args.color || 'var(--accent-color)';
const sizes = { sm: '340px', md: '440px', lg: '560px' };
const width = sizes[String(args.size || 'md').toLowerCase()] || '440px';
const dir = String(args.direction || 'clockwise').toLowerCase() === 'counter' ? -1 : 1;
const numbered = String(args.numbered) === 'true';
const secs = sections.map((s) => (s || '').trim()).filter(Boolean);
const n = secs.length || 1;
const R = 41; // ring radius as % of the square container
let nodes = '';
secs.forEach((s, i) => {
  const ang = (-90 + dir * i * 360 / n) * Math.PI / 180; // clockwise (or counter) from top
  const x = (50 + R * Math.cos(ang)).toFixed(2);
  const y = (50 + R * Math.sin(ang)).toFixed(2);
  const num = numbered ? `<div class="mdp-cy-num">${i + 1}</div>` : '';
  nodes += `<div class="mdp-cy-node" style="left:${x}%; top:${y}%;">${num}<div class="mdp-cy-inner">\n\n${s}\n\n</div></div>`;
});
const center = (args.center || '').trim() ? `<div class="mdp-cy-center">\n\n${args.center.trim()}\n\n</div>` : '';
return `\n\n<div class="mdp-mod-cycle" style="--cy-color:${color}; width: min(100%, ${width});"><div class="mdp-cy-ring"></div>${center}${nodes}</div>\n\n`;
